    assert len(result.choices) == 1  # noqa: S101
    assert result.choices[0].message.tool_calls  # noqa: S101
    assert _alef_e2e_text(result.choices[0].message.tool_calls[0].function.name).lower() == "get_weather".lower()  # noqa: S101
    assert _alef_e2e_text(result.choices[0].finish_reason).lower() == "tool_calls".lower()  # noqa: S101


